import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg,#0f172a,#1e293b)',
      padding: 20,
      fontFamily: 'Poppins, sans-serif'
    }}>
      <div style={{ width: '100%', maxWidth: 430 }}>

        {/* HEADER */}
        <div style={{ textAlign: 'center', marginBottom: 30 }}>
          <h1 style={{
            fontSize: 32,
            fontWeight: '700',
            background: 'linear-gradient(90deg,#22c55e,#4ade80)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            marginBottom: 6
          }}>
            ⚡ TeamTask
          </h1>
          <p style={{ color: '#94a3b8', fontSize: 14 }}>
            Manage your team smarter 🚀
          </p>
        </div>

        {/* CARD */}
        <div style={{
          background: '#1e293b',
          padding: 28,
          borderRadius: 16,
          boxShadow: '0 20px 40px rgba(0,0,0,0.4)',
          border: '1px solid #334155'
        }}>
          <h2 style={{
            textAlign: 'center',
            marginBottom: 20,
            fontSize: 20,
            color: '#f1f5f9',
            fontWeight: 600
          }}>
            Welcome Back 👋
          </h2>

          <form onSubmit={handleSubmit}>

            {/* EMAIL */}
            <div style={{ marginBottom: 16 }}>
              <label style={{ fontSize: 13, color: '#cbd5f5' }}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '11px 12px',
                  marginTop: 5,
                  borderRadius: 8,
                  border: '1px solid #475569',
                  background: '#0f172a',
                  color: '#f1f5f9',
                  fontSize: 13,
                  outline: 'none'
                }}
              />
            </div>

            {/* PASSWORD */}
            <div style={{ marginBottom: 18 }}>
              <label style={{ fontSize: 13, color: '#cbd5f5' }}>Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '11px 12px',
                  marginTop: 5,
                  borderRadius: 8,
                  border: '1px solid #475569',
                  background: '#0f172a',
                  color: '#f1f5f9',
                  fontSize: 13,
                  outline: 'none'
                }}
              />
            </div>

            {/* BUTTON */}
            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '11px',
                borderRadius: 8,
                border: 'none',
                background: 'linear-gradient(90deg,#22c55e,#16a34a)',
                color: '#fff',
                fontSize: 14,
                fontWeight: 600,
                cursor: 'pointer',
                transition: '0.3s'
              }}
            >
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>

          </form>

          {/* REGISTER */}
          <p style={{
            textAlign: 'center',
            marginTop: 16,
            fontSize: 13,
            color: '#94a3b8'
          }}>
            No account? <Link to="/register" style={{ color: '#22c55e', fontWeight: 600 }}>Register</Link>
          </p>
        </div>

        {/* INFO BOX */}
        <div style={{
          marginTop: 16,
          padding: 14,
          background: '#0f172a',
          borderRadius: 10,
          border: '1px solid #334155'
        }}>
          <p style={{ fontSize: 12, color: '#94a3b8' }}>
            💡 Use <span style={{ color: '#22c55e' }}>admin</span> to manage projects and <span style={{ color: '#38bdf8' }}>member</span> to complete tasks
          </p>
        </div>

      </div>
    </div>
  );
}
